var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"2021년\\n<color=#ff3636>관리실패</color> 3년 전","JPN":"2021年\\n<color=#ff3636>管理失敗</color>より3年前","ENG":"[[","TWN":"2021年\\n<color=#ff3636>管理失敗</color>3年前","SCN":"2021年\\n<color=#ff3636>管理失败</color>3年前","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"현장에서 뉴스 속보 보내드리겠습니다.","JPN":"現場から速報です。","ENG":"Breaking news.","TWN":"這是記者現場直播。"},"stage":{"bg":"MAINSTREAM_NEW_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"지금 센트럴 시티 인근에 한 병원에서 화재가 발생했습니다.","JPN":"セントラルシティ近隣の病院から火災が発生しました。","ENG":"A hospital near Central City is caught in flames.","TWN":"位於中心城附近的一家醫院發生火災。"},"stage":{"bg":"MAINSTREAM_NEW_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"퇴근 시간과 겹쳐 상당한 교통체증이 예상되는데요.","JPN":"帰宅ラッシュと重なるため渋滞が予想されます。","ENG":"Significant traffic congestion is to be expected as people finish work and leave for the day.","TWN":"由於正好趕上下班晚高峰，預計該區域將出現嚴重的交通堵塞。"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"게다가 현장으로 통하는 골목길이 너무 좁아서 소방 차량 진입이 어렵다고 합니다.","JPN":"さらには現場前の路地が狭すぎるため、消防車両の進入も難しい状況とのことです。","ENG":"Furthermore, firetrucks are having difficulty maneuvering through the narrow roads leading to the scene of the fire.","TWN":"此外，通往火災現場的巷子十分狹窄，給消防車的進入帶來了極大的困難。"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"부디, 무사히 화재가 진압되길 바라겠습니다!","JPN":"火災が鎮圧し次第、続報をお届けいたします！","ENG":"We all hope that the fire is put out safely!","TWN":"希望這場大火能夠儘快得到安全有效的控制！"},"stage":{"bg":"HELI_NIGHT_2","slots":{"L":null,"C":{"char_id":"REPORTER_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"차량 지원 오는 거 기다리면 한 세월이야!","JPN":"車両支援を待っている状況じゃない！","ENG":"Waiting for backup is going to take hours!","TWN":"等支援車輛抵達，不知道要等到什麼時候！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"다른 팀은 초도 대응 중이다! 구조팀은 당장 장비 챙겨서 나를 따라오도록!","JPN":"他のチームは初動対応中だ！　救助チームは装備を持ってついてこい！","ENG":"The other teams are currently responding first! Rescue team, grab your gear now and follow me!","TWN":"其他隊伍已經開始行動了！救援隊立即收拾裝備，跟我來！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_MEMBER","text":{"KOREA":"네! 알겠습니다!","JPN":"了解しました！","ENG":"Yes, sir!","TWN":"是！明白！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"다들 명심해. 자기 목숨을 소홀하게 여기지 말도록.","JPN":"皆、自分の命を疎かにするな。肝に銘じておけ。","ENG":"Everyone, take precautions and remember not to neglect your own life.","TWN":"大家記住。珍惜自己的生命。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"훌륭한 소방관이라면, 구조자의 목숨과 자신의 목숨……. 어느 쪽도 놓치지 않는다.","JPN":"立派な消防士なら、救助者の命と自分の命……どっちも取りこぼさない。","ENG":"An excellent firefighter knows how to save both... the rescuee's and the rescuer's lives.","TWN":"一名優秀的消防員，求救者和自己的生命……任何一方都不能放棄。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"마지막까지 최선을 다하되, 자기 목숨까지 버리지는 말아라.","JPN":"最後までベストを尽くせ。だが、自分の命も守るんだ。","ENG":"I'm telling you to do your best until the very end, but not throw away your own life.","TWN":"竭盡我們最大的努力，但不許把自己的命也賠進去！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"알아듣겠냐!","JPN":"わかったか！","ENG":"You got that?!","TWN":"都聽明白了嗎！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_MEMBER","text":{"KOREA":"네! 알겠습니다!","JPN":"はい！　了解しました！","ENG":"Yes, sir!","TWN":"是！明白！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"그나저나 이 꼴통은 뭐 하는데 이렇게 늦는 거야?","JPN":"ところであのバカ遅いな。何やってんだ？","ENG":"Anyway, what's taking that knucklehead so long?","TWN":"說起來，那個臭丫頭在做什麼，怎麼還沒來？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_NULL","text":{"KOREA":"어, 그게…….","JPN":"ええと、それが……","ENG":"Err, well…","TWN":"呃，那個……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_NULL","text":{"KOREA":"제일 먼저 도착했는데, 슥 둘러보더니 어디론가 사라졌습니다.","JPN":"着いたのは一番早かったんですが、周りを見渡してからどこかに消えました。","ENG":"She was the first to arrive at the scene. She took a look around before disappearing.","TWN":"她好像來得最早，到處看了一圈，就不知道跑去哪裡了。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"그 자식이? 나 참, 또 무슨 사고를 치려고.","JPN":"あいつが？　ったく、また何をやらかす気だ。","ENG":"That rascal. Ugh, who knows what trouble she's gonna get herself into this time.","TWN":"那傢伙？真是的，又要闖什麼禍。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_NULL","text":{"KOREA":"호출할까요?","JPN":"呼び戻しましょうか？","ENG":"Should I radio her?","TWN":"要呼叫她嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"됐어, 정신머리는 똑바로 박힌 녀석이니까 나름 생각이 있겠지.","JPN":"いや、いい。ああ見えてしっかりしてるやつだし、何か考えがあるんだろう。","ENG":"No. She's smart enough to know what she's doing.","TWN":"算了，那傢伙頭腦清醒得很，她大概有自己的想法吧。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_NULL","text":{"KOREA":"대장님! 입원 환자 명단 파악 완료하였습니다!","JPN":"隊長！　入院患者のリストを入手しました！","ENG":"Captain! We got the inpatient list!","TWN":"隊長！拿到住院患者名單了！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"좋아! 구조팀, 준비해!","JPN":"よし！　救助チーム、準備しろ！","ENG":"Good! Rescue team, get ready!","TWN":"好的！救援隊，做好準備！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"제길, 불길이 너무 거세서 입구로는 못 들어간다!","JPN":"くそ、火が強すぎて入り口からは入れない！","ENG":"Dammit, the fire's too strong! We can't go in through the entrance!","TWN":"可惡，火這麼大，我們根本進不去！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};